-- 045_ai_research_strategy_skills.sql
-- Internal AI research, strategy, productivity, and analysis skills.
-- These skills use saved context and user-provided text only. They do not
-- browse, create Web Operator actions, send, post, or publish.

ON CONFLICT (skill_id) DO UPDATE SET
  name = EXCLUDED.name,
  category = EXCLUDED.category,
  description = EXCLUDED.description,
  input_schema = EXCLUDED.input_schema,
  output_schema = EXCLUDED.output_schema,
  safety_level = EXCLUDED.safety_level,
  enabled = EXCLUDED.enabled,
  updated_at = NOW();
